public class TimedExecutor
{
    public T ExecuteWithTimeout<T>(Func<T> work, TimeSpan timeout)
    {
        // CancellationTokenSource replaces Thread.Abort for timeout enforcement.
        // CancelAfter schedules automatic cancellation — no manual abort needed.
        using var cts = new CancellationTokenSource(timeout);

        try
        {
            // Task.Run schedules work on the thread pool.
            // .WaitAsync(token) makes the *wait* cancellable — if the timeout
            // fires, we stop waiting immediately and throw OperationCanceledException.
            return Task.Run(() => work(), cts.Token)
                       .WaitAsync(cts.Token)    // .NET 6+ API
                       .GetAwaiter()
                       .GetResult();
        }
        catch (OperationCanceledException) when (cts.IsCancellationRequested)
        {
            // Replaces the old: catch (ThreadAbortException) { Thread.ResetAbort(); }
            // We know it was our timeout, not an external cancellation.
            throw new TimeoutException(
                $"Operation exceeded {timeout.TotalSeconds}s timeout");
        }
    }

